                                                <div className="flex flex-col items-end gap-1">
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        className="text-[10px] uppercase tracking-widest font-black text-foreground hover:text-primary transition-colors h-auto p-0 hover:bg-transparent shadow-none"
                                                    >
                                                        {t("cta_pricing")}
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        className="text-[10px] uppercase tracking-widest font-black text-foreground hover:text-primary transition-colors h-auto p-0 hover:bg-transparent shadow-none"
                                                    >
