                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                </Container>
            </section>

            {/* Expert Insights (FAQ) */}
            <section id="faq" className="py-24 bg-muted/20 border-y border-border transition-colors duration-300">
