                    </span>
                  </div>
                </div>
              )}
            </div>

            {/* Signals + stats */}
            <div className="space-y-6">
              {/* Signal chips */}
              {currentFrame && (
                <div className="space-y-3">
                  <span className="text-[10px] font-black text-foreground/60 uppercase tracking-widest block">
                    {t('detected_signals')}
                  </span>
                  <div className="flex flex-wrap gap-2">
                    {currentFrame.signals.filter(s => s.detected).map(sig => (
                      <span
                        key={sig.id}
                        className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-black border shadow-sm bg-rose-500/15 border-rose-500/30 text-rose-500 dark:text-rose-400"
                      >
                        <AlertCircle className="w-3.5 h-3.5" />
                        {/* Try to translate the ID, fall back to name provided by engine */}
                        {t.has(`signal_${sig.id}_name`) ? t(`signal_${sig.id}_name`) : sig.name}
                      </span>
                    ))}
                    {currentFrame.signals.every(s => !s.detected) && (
                      <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-black border shadow-sm bg-emerald-500/15 border-emerald-500/30 text-emerald-600 dark:text-emerald-400">
                        <CheckCircle2 className="w-3.5 h-3.5" />
                        {tCommon('anomaly_low_risk')}
                      </span>
                    )}
                  </div>
                </div>
              )}

              {/* Legacy signals fallback */}
              {!currentFrame &&
                result.frameReports[selectedFrame]?.report.pixelLogicSignals && (
                  <div>
                    <span className="text-[10px] font-black text-foreground/60 uppercase tracking-widest block mb-3">
                      {t('signal_methodology')}
                    </span>
                    <div className="grid grid-cols-2 gap-3">
                      {result.frameReports[
                        selectedFrame
                      ].report.pixelLogicSignals.map((sig: any) => (
                        <div
                          key={sig.id}
                          className="p-3 rounded-xl border border-zinc-100 dark:border-zinc-900 flex flex-col justify-center items-center text-center"
                        >
                          <span className="text-[9px] font-black text-foreground/60 uppercase tracking-widest mb-1">
                            {sig.label}
                          </span>
                          <span
                            className={`text-sm font-black font-mono ${sig.risk === 'flag'
                              ? 'text-rose-500'
                              : sig.risk === 'concern'
                                ? 'text-amber-500'
                                : 'text-emerald-500'
                              }`}
                          >
                            {sig.detectedValue}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

              {/* Pixel stats strip */}
              {currentStats && (
                <div className="space-y-2">
                  <span className="text-[10px] font-black text-foreground/60 uppercase tracking-widest block">
                    {t('frame_pixel_stats')}
                  </span>
                  <div className="grid grid-cols-2 gap-2">
                    {[
                      {
                        labelKey: 'stat_noise',
                        value: (currentStats.noiseLevel ?? 0).toFixed(1),
                        warn: (currentStats.noiseLevel ?? 0) < 14,
                      },
                      {
                        labelKey: 'stat_uniformity',
                        value: ((currentStats.colorUniformity ?? 0) * 100).toFixed(0),
                        unit: '%',
                        warn: (currentStats.colorUniformity ?? 0) > 0.76,
                      },
                      {
                        labelKey: 'stat_edge_sharp',
                        value: (currentStats.edgeSharpness ?? 0).toFixed(1),
                        warn: (currentStats.edgeSharpness ?? 0) < 7,
                      },
                      {
                        labelKey: 'stat_brightness',
                        value: (currentStats.avgBrightness ?? 0).toFixed(0),
                      },
                      {
                        labelKey: 'stat_center_sharp',
                        value: (currentStats.centerSharpness ?? 0).toFixed(1),
                      },
                      {
                        labelKey: 'stat_border_sharp',
                        value: (currentStats.borderSharpness ?? 0).toFixed(1),
                        warn:
                          (currentStats.centerSharpness ?? 0) > 0 &&
                          (currentStats.borderSharpness ?? 0) <
                          (currentStats.centerSharpness ?? 0) * 0.45,
                      },
                      {
                        labelKey: 'stat_color_blocks',
                        value: String(currentStats.localColorBlocks ?? 0),
                        warn: (currentStats.localColorBlocks ?? 0) < 18,
                      },
                      {
                        labelKey: 'stat_bg_variance',
                        value: (currentStats.bgZoneVariance ?? 0).toFixed(1),
                        warn: (currentStats.bgZoneVariance ?? 0) > 8,
                      },
                    ].map(({ labelKey, value, unit = '', warn }) => (
                      <StatPill
                        key={labelKey}
                        label={t(labelKey)}
                        value={value}
                        unit={unit}
                        warn={warn}
                      />
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </motion.div>
      </AnimatePresence>

      {/* â”€â”€ Native AI Forensic Scouts (Deep ML) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */}
      {result.deepMl && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="p-8 rounded-[2.5rem] bg-gradient-to-br from-blue-500/5 to-emerald-500/5 border border-blue-500/10 shadow-sm space-y-6"
        >
          <div className="flex items-center justify-between border-b border-blue-500/10 pb-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-500/10 rounded-2xl border border-blue-500/20">
                <Scan className="w-5 h-5 text-blue-500" />
              </div>
              <div>
                <h4 className="text-sm font-black uppercase tracking-[0.2em] text-blue-500/80">
                  {tCommon("biometric_scouts")}
                </h4>
                <p className="text-xs text-foreground/60 font-medium">
                  {t('deep_analysis_desc')}
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2 px-4 py-1.5 bg-white/50 dark:bg-black/50 rounded-full border border-border/50">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-tight text-foreground/60 italic">
                {tCommon("zero_api_notice")}
              </span>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Biometric Results */}
            <div className="space-y-4">
              <span className="text-[10px] font-black text-foreground/60 uppercase tracking-widest flex items-center gap-2">
                <Fingerprint className="w-4 h-4" />
                {t('anatomical_consistency')}
              </span>
              <div className="flex flex-wrap gap-2">
                {result.deepMl.biometrics.faceAnomalies.length > 0 || result.deepMl.biometrics.handAnomalies.length > 0 ? (
                  ([...result.deepMl.biometrics.faceAnomalies, ...result.deepMl.biometrics.handAnomalies] as ForensicAnomaly[]).map((anomaly: any, idx) => (
                    <div key={idx} className="flex items-center gap-2 px-3 py-1.5 bg-rose-500/15 border border-rose-500/30 rounded-xl text-[11px] font-black text-rose-500 dark:text-rose-400 shadow-sm">
                      <AlertTriangle className="w-3.5 h-3.5" />
                      {t.has(`anomaly_${anomaly.id}_name`) ? t(`anomaly_${anomaly.id}_name`) : anomaly.name}
                    </div>
                  ))
                ) : (
                  <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/15 border border-emerald-500/30 rounded-xl text-[11px] font-black text-emerald-600 dark:text-emerald-400 shadow-sm">
                    <CheckCircle2 className="w-3.5 h-3.5" />
                    {tCommon("anomaly_low_risk")}
                  </div>
                )}
              </div>
            </div>

            {/* OCR / Text Layer */}
            <div className="space-y-4">
              <span className="text-[10px] font-black text-foreground/60 uppercase tracking-widest flex items-center gap-2">
                <FileText className="w-4 h-4" />
                {tCommon("ocr_detect")}
              </span>
              <div className="p-4 bg-zinc-100 dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800">
                <div className="flex items-center justify-between mb-3">
                  <span className="text-[10px] font-bold text-foreground/60 uppercase">{t('pixel_pattern_ocr')}</span>
                  <span className={`text-[10px] font-black px-2 py-0.5 rounded ${result.deepMl.ocr.isGarbled ? 'bg-rose-500 text-white' : 'bg-emerald-500 text-white'}`}>
                    {result.deepMl.ocr.isGarbled ? t('status_suspicious') : t('status_clean')}
                  </span>
                </div>
                <p className="text-xs font-mono leading-relaxed opacity-60">
                  {result.deepMl.ocr.text || t('no_text_in_frame')}
                </p>
              </div>
            </div>
          </div>

          {/* Watermarks */}
          {result.deepMl.watermarks.length > 0 && (
            <div className="pt-4 border-t border-blue-500/5">
              <div className="flex items-center gap-3 px-4 py-3 bg-amber-500/5 border border-amber-500/10 rounded-2xl">
                <Layers className="w-4 h-4 text-amber-600" />
                <span className="text-xs font-bold text-amber-700 dark:text-amber-500">
                  {t('detected_ai_signature')}: <span className="font-black italic">
                    {(result.deepMl.watermarks as ForensicAnomaly[]).map((w: any) => t.has(`watermark_${w.id}_name`) ? t(`watermark_${w.id}_name`) : w.name).join(', ')}
