        sheet.columns = [
            { header: translations.Reports?.col_date || 'Date', key: 'date', width: 15 },
            { header: translations.Reports?.col_title || 'Title', key: 'title', width: 50 },
            { header: translations.Reports?.col_source || 'Source', key: 'source', width: 20 },
